body,
html {
    height: 100%;
    width: 100%;
    display: flex;
    flex-direction: row;
    overflow: hidden;
    font-family: "Inter", Helvetica, Arial, sans-serif;
    font-size: 16px;
    margin: 0;
}

main[role=main] {
    flex: 1 1 100%;
    height: calc(100% - 24px);
