    margin-right: auto;
    animation: fade-in-keyframes 0.5s;
    border-bottom: none;
}

footer {
    font-size: 75%;
    border-top: solid 1px #ccc;
    line-height: 24px;
    height: 24px;
    clear: both;
    position: absolute;
    bottom: 0;
    left: 0;
    right: 0;
    z-index: 1;
    padding-left: 8px;
    background-color: #fafafa;
}

