        display: initial;
    }
}

.desktop {
    display: initial;
}

@media (max-width: 768px),
(max-device-width: 768px) {
    .desktop {
        display: none;
    }
}

@media (max-width: 768px),
(max-device-width: 768px) {

    html,
    body {
        font-size: initial;
    }

    main[role=main] {
        padding-right: 40px;
    }

    main[role=main] figure img {
        max-width: 100%;
    }

    nav[role=toc] {
        display: none;
    }

    body {
        flex-wrap: wrap;
    }

    main[role=main] {
        flex: 1 1 calc(100% - 40px - 45px);
    }

    #search {
        flex: 0 0 100%;
        order: -1;
        max-width: 100%;
        width: 100%;
        opacity: 1;
    }

    #search.hidden {
        display: block;
        position: absolute;
        right: 0px;
        width: auto;
        height: auto;
    }

    #search.hidden #search-input {
        height: auto;
    }

    #search.hidden #search-input input {
        width: 0px;
        margin: 8px 0px;
    }

    #search.hidden #search-input input + #close-icon {
        display: none;
    }

    #search.hidden #search-results {
        height: auto;
        display: none;
    }

    #search-input {
        position: initial;
        height: auto;
    }

    #search-input input,
    #search-input input:focus,
    #search-input input:hover {
        width: calc(100% - 5em);
    }

    #search-results {
        position: initial;
        height: auto;
    }
}

@media only screen and (orientation: portrait) and (max-device-width: 768px) {
    body {
        -webkit-text-size-adjust: 100%;
        font-size: 3em;
    }

    footer {
        font-size: x-large;
        line-height: calc(24px * 2);
        height: calc(24px * 2);
    }
}

